import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { sendCampaign } from "@/lib/campaigns";
import { requireGarageAccess, requireSession } from "@/lib/auth-guards";
import { isAdminRole } from "@/lib/session";

export async function POST(request: Request) {
  try {
    const sessionResult = await requireSession(request);
    if ("response" in sessionResult) return sessionResult.response;

    const { searchParams } = new URL(request.url);
    const garageId = String(searchParams.get("garageId") || "").trim();
    const now = new Date();

    if (garageId) {
      const guard = await requireGarageAccess(request, garageId);
      if ("response" in guard) return guard.response;
    } else if (!isAdminRole(sessionResult.session.role)) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const campaigns = await prisma.campaign.findMany({
      where: {
        status: "SCHEDULED",
        scheduledFor: { lte: now },
        ...(garageId ? { garageId } : {}),
      },
      orderBy: { scheduledFor: "asc" },
    });

    const results = [] as Array<{ id: string; sentCount: number; failedCount: number; skippedCount: number }>;

    for (const campaign of campaigns) {
      const result = await sendCampaign({
        campaignId: campaign.id,
        originHeader: request.headers.get("origin"),
      });
      results.push({ id: campaign.id, ...result });
    }

    return NextResponse.json({ processed: results.length, results });
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    return NextResponse.json(
      { error: "Failed to process campaigns", details: message },
      { status: 500 }
    );
  }
}
